The below solution is corrected and tested to check if it works:

public static int levenshtein(String source, String target) {
    if (source.isEmpty() || target.isEmpty()) {
        return source.isEmpty() ? target.length() : source.length();
    } else if (source.charAt(0) == target.charAt(0)) {
        return 1 + levenshtein(source.substring(1), target.substring(1));
    } else {
        int deletion = levenshtein(source, target.substring(1));
        int insertion = levenshtein(source.substring(1), target);
        int substitution = levenshtein(source.substring(1), target.substring(1));
        if (deletion < insertion && deletion < substitution) {
            return deletion + 1;
        } else if (insertion < substitution) {
            return insertion + 1;
        } else {
            return substitution + 1;
        }
    }
}

